}

arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now respects the UTF-8 flag,
        // which changes how non-ASCII names are encoded. Since the consuming
        // Java system reads filenames in Shift-JIS, explicitly specify the encoding.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, Encoding.GetEncoding("Shift-JIS"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

